<template>
  <div class="vertical">
    <h4>각종 옵션 적용 슬라이드</h4>
    <img src="../assets/images/codeExample/options.jpg" alt="">
    <div class="options-slider">
      <div class="slider-wrapper">
        <div class="slider-slide"><img src="../assets/images/horizontal1.jpg" alt="" loading="lazy"></div>
        <div class="slider-slide"><img src="../assets/images/horizontal11.jpg" alt="" loading="lazy"></div>
        <div class="slider-slide"><img src="../assets/images/vertical7.jpg" alt="" loading="lazy"></div>
        <div class="slider-slide"><img src="../assets/images/horizontal12.jpg" alt=""></div>
        <div class="slider-slide"><img src="../assets/images/vertical8.jpg" alt=""></div>
        <div class="slider-slide"><img src="../assets/images/vertical2.jpg" alt=""></div>
      </div>
      <div class="slider-arrow__prev"></div>
      <div class="slider-arrow__next"></div>
      <div class="slider-pagination"></div>
    </div>
  </div>
</template>

<script>
import PureJsSlider from '../assets/js/pure-js-slider.mjs'
import '../assets/css/pure-js-slider.css'

export default {
  name: 'OptionsSlider',
  components: {},
  setup () {
    const sliderLog = () => {}
    return {
      sliderLog
    }
  },
  mounted () {
    const mySlider3 = new PureJsSlider('.options-slider', {
      init: true,
      direction: 'horizontal',
      useArrow: {
        enabled: true,
        followDirection: true
      },
      userSetting: false,
      autoplay: {
        enabled: true,
        // delay 값이 transitionSpeed보다 길어야 정상작동함.
        delay: 2000,
        toForward: true,
        pauseOnInteraction: true
      },
      touchMove: {
        enabled: true
      },

      width: 900,
      // height: ,
      transitionSpeed: 700
    })
    this.sliderLog(mySlider3)
  }
}
</script>
