import { createRouter, createWebHistory } from 'vue-router'
import ReadMe from '../views/ReadMeView.vue'
import PureJsSlider from '../views/PureJsSlider.vue'
import Options from '../views/OptionsView.vue'

const routes = [
  {
    path: '/',
    name: 'readme',
    component: ReadMe
  },
  {
    path: '/default',
    name: 'default',
    component: PureJsSlider
  },
  {
    path: '/vertical',
    name: 'vertical',
    // route level code-splitting
    // this generates a separate chunk (about.[hash].js) for this route
    // which is lazy-loaded when the route is visited.
    component: () => import(/* webpackChunkName: "about" */ '../views/VerticalView.vue')
  },
  {
    path: '/options',
    name: 'options',
    component: Options
  }
]

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes
})

export default router
